  function tx(key){if(routeLang!=='zh')return key;var m={'Copied':'\u5df2\u590d\u5236','Copied to clipboard':'\u5df2\u590d\u5236\u5230\u526a\u8d34\u677f','Tint':'\u6d45\u8272','Shade':'\u6df1\u8272','Shades':'\u6df1\u8272','Tints':'\u6d45\u8272','Tone':'\u7070\u8c03','Tones':'\u7070\u8c03','Analogous':'\u7c7b\u4f3c\u8272','Complement':'\u4e92\u8865','Complementary':'\u4e92\u8865\u8272','Split':'\u5206\u88c2','Split Complementary':'\u5206\u88c2\u4e92\u8865','Split complementary':'\u5206\u88c2\u4e92\u8865','Triadic':'\u4e09\u8272','Tetradic':'\u56db\u8272','Square':'\u65b9\u5f62\u914d\u8272','History':'\u5386\u53f2\u8bb0\u5f55','Clear':'\u6e05\u9664','No colors yet':'\u6682\u65e0\u989c\u8272','Export':'\u5bfc\u51fa','Code':'\u4ee3\u7801','Value':'\u503c','Toggle':'\u6298\u53e0','White background':'\u767d\u8272\u80cc\u666f','Black background':'\u9ed1\u8272\u80cc\u666f','contrast ratio on a black background':'\u9ed1\u8272\u80cc\u666f\u5bf9\u6bd4\u5ea6','contrast ratio on a white background':'\u767d\u8272\u80cc\u666f\u5bf9\u6bd4\u5ea6','Element':'\u5143\u7d20','Small text':'\u5c0f\u5b57\u53f7\u6587\u672c','Large text':'\u5927\u5b57\u53f7\u6587\u672c','UI element':'\u754c\u9762\u5143\u7d20','Protanopia':'\u7ea2\u8272\u76f2','Deuteranopia':'\u7eff\u8272\u76f2','Tritanopia':'\u84dd\u9ec4\u8272\u76f2','Achromatopsia':'\u5168\u8272\u76f2','Choose harmony...':'\u9009\u62e9\u548c\u8c10\u914d\u8272...'};return m[key]||key}
  var zhText={
    'Using the Color Picker':'\u4f7f\u7528\u989c\u8272\u53d6\u8272\u5668',
    'Use this color picker to choose a color visually, type a value directly, sample colors from an image, or explore palettes from the color wheel. The current color is converted into Hex, RGB, HSL, HSV, and OKLCH so it can move cleanly between CSS, design tools, and exported code.':'\u4f7f\u7528\u8fd9\u4e2a\u53d6\u8272\u5668\u53ef\u4ee5\u53ef\u89c6\u5316\u9009\u62e9\u989c\u8272\u3001\u76f4\u63a5\u8f93\u5165\u6570\u503c\u3001\u4ece\u56fe\u7247\u53d6\u6837\uff0c\u6216\u901a\u8fc7\u8272\u8f6e\u63a2\u7d22\u8c03\u8272\u677f\u3002\u5f53\u524d\u989c\u8272\u4f1a\u8f6c\u6362\u4e3a Hex\u3001RGB\u3001HSL\u3001HSV \u548c OKLCH\uff0c\u65b9\u4fbf\u5728 CSS\u3001\u8bbe\u8ba1\u5de5\u5177\u548c\u5bfc\u51fa\u4ee3\u7801\u4e4b\u95f4\u4f7f\u7528\u3002',
    'Using the Hex Color Picker':'\u4f7f\u7528 Hex \u989c\u8272\u53d6\u8272\u5668',
    'The picker lets you move through the color field by dragging the selection point, editing the channel values, or entering a Hex code. As the color changes, the swatches, harmonies, variations, contrast previews, and export panels update from the same selected value.':'\u4f60\u53ef\u4ee5\u62d6\u52a8\u9009\u62e9\u70b9\u3001\u7f16\u8f91\u901a\u9053\u6570\u503c\uff0c\u6216\u8f93\u5165 Hex \u4ee3\u7801\u6765\u9009\u62e9\u989c\u8272\u3002\u989c\u8272\u53d8\u5316\u65f6\uff0c\u8272\u5757\u3001\u548c\u8c10\u914d\u8272\u3001\u989c\u8272\u53d8\u5316\u3001\u5bf9\u6bd4\u5ea6\u9884\u89c8\u548c\u5bfc\u51fa\u9762\u677f\u90fd\u4f1a\u57fa\u4e8e\u540c\u4e00\u4e2a\u5f53\u524d\u503c\u540c\u6b65\u66f4\u65b0\u3002',
    'How Many Hex Colors Are There?':'Hex \u989c\u8272\u6709\u591a\u5c11\u79cd\uff1f',
    'A Hex color uses six hexadecimal characters in the form #RRGGBB. Each pair controls red, green, or blue from 00 to FF, which gives web designers 16,777,216 possible RGB colors.':'Hex \u989c\u8272\u4f7f\u7528 #RRGGBB \u5f62\u5f0f\u7684\u516d\u4f4d\u5341\u516d\u8fdb\u5236\u5b57\u7b26\u3002\u6bcf\u4e24\u4f4d\u5206\u522b\u63a7\u5236\u7ea2\u3001\u7eff\u3001\u84dd\u901a\u9053\uff0c\u8303\u56f4\u4ece 00 \u5230 FF\uff0c\u56e0\u6b64\u7f51\u9875\u8bbe\u8ba1\u4e2d\u53ef\u4f7f\u7528 16,777,216 \u79cd RGB \u989c\u8272\u3002',
    'Image Color Picker':'\u56fe\u7247\u53d6\u8272\u5668',
    'The image picker can sample colors directly from an uploaded picture. Move any pick point over the image to capture a color, compare the sampled values, and export the selected image colors without leaving the page.':'\u56fe\u7247\u53d6\u8272\u5668\u53ef\u4ee5\u76f4\u63a5\u4ece\u4e0a\u4f20\u56fe\u7247\u4e2d\u53d6\u6837\u3002\u79fb\u52a8\u4efb\u610f\u53d6\u8272\u70b9\u5373\u53ef\u6355\u83b7\u989c\u8272\u3001\u6bd4\u8f83\u53d6\u6837\u503c\uff0c\u5e76\u5728\u4e0d\u79bb\u5f00\u9875\u9762\u7684\u60c5\u51b5\u4e0b\u5bfc\u51fa\u9009\u4e2d\u7684\u56fe\u7247\u989c\u8272\u3002',
    'Color Wheel':'\u8272\u8f6e',
    'The color wheel is useful when you want to work by hue. Drag around the outer ring to change the hue, then adjust the inner area to refine saturation and brightness while keeping the rest of the interface synchronized.':'\u5f53\u4f60\u60f3\u6309\u8272\u76f8\u5de5\u4f5c\u65f6\uff0c\u8272\u8f6e\u975e\u5e38\u6709\u7528\u3002\u62d6\u52a8\u5916\u73af\u6539\u53d8\u8272\u76f8\uff0c\u518d\u8c03\u6574\u5185\u90e8\u533a\u57df\u6765\u7ec6\u5316\u9971\u548c\u5ea6\u548c\u4eae\u5ea6\uff0c\u540c\u65f6\u4fdd\u6301\u6574\u4e2a\u754c\u9762\u540c\u6b65\u3002',
    'Color Shades, Tints, and Tones':'\u989c\u8272\u9634\u5f71\u3001\u6d45\u8272\u548c\u8272\u8c03',
    'Shades mix the selected color with black, tints mix it with white, and tones move the color toward gray. These variations are useful for hover states, borders, backgrounds, disabled states, and layered interface surfaces.':'\u9634\u5f71\u4f1a\u628a\u5f53\u524d\u8272\u4e0e\u9ed1\u8272\u6df7\u5408\uff0c\u6d45\u8272\u4f1a\u4e0e\u767d\u8272\u6df7\u5408\uff0c\u8272\u8c03\u4f1a\u8ba9\u989c\u8272\u9760\u8fd1\u7070\u8272\u3002\u8fd9\u4e9b\u53d8\u5316\u9002\u7528\u4e8e\u60ac\u505c\u72b6\u6001\u3001\u8fb9\u6846\u3001\u80cc\u666f\u3001\u7981\u7528\u72b6\u6001\u548c\u5206\u5c42\u754c\u9762\u3002',
    'Color Harmonies':'\u989c\u8272\u548c\u8c10',
    'Harmony palettes are built from relationships on the color wheel. Analogous, complementary, split complementary, triadic, tetradic, and square combinations give you fast starting points for brand palettes, UI accents, data colors, and illustration systems.':'\u548c\u8c10\u8c03\u8272\u677f\u57fa\u4e8e\u8272\u8f6e\u4e0a\u7684\u5173\u7cfb\u751f\u6210\u3002\u7c7b\u4f3c\u8272\u3001\u4e92\u8865\u8272\u3001\u5206\u88c2\u4e92\u8865\u8272\u3001\u4e09\u8272\u3001\u56db\u8272\u548c\u65b9\u5f62\u7ec4\u5408\uff0c\u53ef\u4ee5\u5feb\u901f\u4f5c\u4e3a\u54c1\u724c\u914d\u8272\u3001\u754c\u9762\u5f3a\u8c03\u8272\u3001\u6570\u636e\u989c\u8272\u548c\u63d2\u753b\u7cfb\u7edf\u7684\u8d77\u70b9\u3002',
    'Color Spaces':'\u989c\u8272\u7a7a\u95f4',
    'RGB describes screen colors through red, green, and blue light. HSL separates hue, saturation, and lightness, making it easier to adjust a color by feel. HSV is common in visual pickers because it maps naturally to saturation and value. OKLCH is designed to feel more even to human vision, which helps when building modern CSS palettes.':'RGB \u901a\u8fc7\u7ea2\u3001\u7eff\u3001\u84dd\u5149\u63cf\u8ff0\u5c4f\u5e55\u989c\u8272\u3002HSL \u5c06\u8272\u76f8\u3001\u9971\u548c\u5ea6\u548c\u4eae\u5ea6\u5206\u79bb\uff0c\u4fbf\u4e8e\u51ed\u611f\u89c9\u8c03\u6574\u989c\u8272\u3002HSV \u5e38\u7528\u4e8e\u53ef\u89c6\u5316\u53d6\u8272\u5668\uff0c\u56e0\u4e3a\u5b83\u81ea\u7136\u5bf9\u5e94\u9971\u548c\u5ea6\u548c\u660e\u5ea6\u3002OKLCH \u66f4\u8d34\u8fd1\u4eba\u773c\u611f\u77e5\uff0c\u5728\u6784\u5efa\u73b0\u4ee3 CSS \u8c03\u8272\u677f\u65f6\u66f4\u7a33\u5b9a\u3002',
    'Hex Codes':'Hex \u4ee3\u7801',
    'Hex codes are compact, easy to copy, and widely supported in browsers and design tools. Because Hex and RGB describe the same red, green, and blue channels, a color can be converted between the two without changing its appearance.':'Hex \u4ee3\u7801\u7b80\u6d01\u3001\u6613\u590d\u5236\uff0c\u5e76\u88ab\u6d4f\u89c8\u5668\u548c\u8bbe\u8ba1\u5de5\u5177\u5e7f\u6cdb\u652f\u6301\u3002\u7531\u4e8e Hex \u548c RGB \u63cf\u8ff0\u7684\u662f\u540c\u4e00\u7ec4\u7ea2\u3001\u7eff\u3001\u84dd\u901a\u9053\uff0c\u4e24\u8005\u4e92\u8f6c\u4e0d\u4f1a\u6539\u53d8\u989c\u8272\u5916\u89c2\u3002',
    'Exporting Color Codes':'\u5bfc\u51fa\u989c\u8272\u4ee3\u7801',
    'Export panels collect the visible palette into formats for Tailwind, Figma, CSS variables, prefixed color functions, and plain code lists. Click a swatch to copy one color, or use the export button when you need the full group.':'\u5bfc\u51fa\u9762\u677f\u53ef\u4ee5\u628a\u5f53\u524d\u53ef\u89c1\u8c03\u8272\u677f\u6574\u7406\u4e3a Tailwind\u3001Figma\u3001CSS \u53d8\u91cf\u3001\u5e26\u524d\u7f00\u7684\u989c\u8272\u51fd\u6570\u548c\u7eaf\u4ee3\u7801\u5217\u8868\u3002\u70b9\u51fb\u8272\u5757\u53ef\u590d\u5236\u5355\u4e2a\u989c\u8272\uff0c\u9700\u8981\u6574\u7ec4\u989c\u8272\u65f6\u4f7f\u7528\u5bfc\u51fa\u6309\u94ae\u3002',
    'WCAG and Accessibility':'WCAG \u4e0e\u65e0\u969c\u788d',
    'Readable color combinations depend on contrast. The contrast checker compares the selected color against light and dark backgrounds so you can choose text, border, and surface colors with accessibility in mind.':'\u53ef\u8bfb\u7684\u914d\u8272\u53d6\u51b3\u4e8e\u5bf9\u6bd4\u5ea6\u3002\u5bf9\u6bd4\u5ea6\u68c0\u67e5\u5668\u4f1a\u6bd4\u8f83\u5f53\u524d\u989c\u8272\u5728\u6d45\u8272\u548c\u6df1\u8272\u80cc\u666f\u4e0a\u7684\u8868\u73b0\uff0c\u5e2e\u52a9\u4f60\u9009\u62e9\u66f4\u6613\u8bfb\u7684\u6587\u5b57\u3001\u8fb9\u6846\u548c\u754c\u9762\u8868\u9762\u989c\u8272\u3002',
    'Color Blindness Simulator':'\u8272\u76f2\u6a21\u62df\u5668',
    'The simulator previews how the current color may shift for common color vision conditions. It helps you avoid palettes that rely only on hue differences and encourages stronger contrast, labels, and secondary visual cues.':'\u6a21\u62df\u5668\u4f1a\u9884\u89c8\u5f53\u524d\u989c\u8272\u5728\u5e38\u89c1\u8272\u89c9\u5dee\u5f02\u4e0b\u53ef\u80fd\u51fa\u73b0\u7684\u53d8\u5316\u3002\u5b83\u80fd\u5e2e\u52a9\u4f60\u907f\u514d\u53ea\u4f9d\u8d56\u8272\u76f8\u5dee\u5f02\u7684\u914d\u8272\uff0c\u5e76\u9f13\u52b1\u4f7f\u7528\u66f4\u5f3a\u7684\u5bf9\u6bd4\u5ea6\u3001\u6807\u7b7e\u548c\u8f85\u52a9\u89c6\u89c9\u63d0\u793a\u3002',
    'Dark and Light Mode Theming':'\u6df1\u8272\u548c\u6d45\u8272\u4e3b\u9898',
    'Shades, tints, tones, and harmony palettes can become the base for dark and light themes. Start with one color, check the surrounding variations, then export the values that work for backgrounds, foregrounds, buttons, and emphasis states.':'\u9634\u5f71\u3001\u6d45\u8272\u3001\u8272\u8c03\u548c\u548c\u8c10\u914d\u8272\u90fd\u53ef\u4ee5\u4f5c\u4e3a\u6df1\u6d45\u4e3b\u9898\u7684\u57fa\u7840\u3002\u4ece\u4e00\u4e2a\u989c\u8272\u5f00\u59cb\uff0c\u68c0\u67e5\u5468\u56f4\u53d8\u5316\uff0c\u518d\u5bfc\u51fa\u9002\u5408\u80cc\u666f\u3001\u524d\u666f\u3001\u6309\u94ae\u548c\u5f3a\u8c03\u72b6\u6001\u7684\u6570\u503c\u3002',
    'Using the Color Wheel':'\u4f7f\u7528\u8272\u8f6e',
    'The color wheel is a visual way to understand how colors relate to one another. It arranges hues around a circle, making it easier to choose a base color, compare nearby colors, and build balanced palettes from predictable relationships.':'\u8272\u8f6e\u662f\u4e00\u79cd\u76f4\u89c2\u7406\u89e3\u989c\u8272\u5173\u7cfb\u7684\u5de5\u5177\u3002\u5b83\u628a\u8272\u76f8\u6392\u5217\u5728\u5706\u73af\u4e0a\uff0c\u65b9\u4fbf\u9009\u62e9\u57fa\u7840\u8272\u3001\u6bd4\u8f83\u76f8\u90bb\u989c\u8272\uff0c\u5e76\u6839\u636e\u53ef\u9884\u6d4b\u7684\u5173\u7cfb\u6784\u5efa\u5e73\u8861\u8c03\u8272\u677f\u3002',
    'What Is a Color Wheel?':'\u4ec0\u4e48\u662f\u8272\u8f6e\uff1f',
    'A color wheel places red, orange, yellow, green, blue, and violet around a circular spectrum. Colors that sit close together usually feel related and gentle, while colors across the wheel create stronger contrast and more energy.':'\u8272\u8f6e\u5c06\u7ea2\u3001\u6a59\u3001\u9ec4\u3001\u7eff\u3001\u84dd\u3001\u7d2b\u6392\u5217\u5728\u5706\u5f62\u5149\u8c31\u4e0a\u3002\u76f8\u90bb\u989c\u8272\u901a\u5e38\u66f4\u534f\u8c03\u67d4\u548c\uff0c\u800c\u76f8\u5bf9\u4f4d\u7f6e\u7684\u989c\u8272\u4f1a\u5f62\u6210\u66f4\u5f3a\u7684\u5bf9\u6bd4\u548c\u80fd\u91cf\u3002',
    'How to Use This Color Wheel':'\u5982\u4f55\u4f7f\u7528\u8fd9\u4e2a\u8272\u8f6e',
    'Drag around the wheel to choose a hue, then adjust the color inside the picker to refine saturation and brightness. The current color updates the Hex, RGB, HSL, HSV, and OKLCH values, the top palette, the harmony swatches, and the export panels.':'\u62d6\u52a8\u8272\u8f6e\u9009\u62e9\u8272\u76f8\uff0c\u518d\u5728\u53d6\u8272\u533a\u57df\u4e2d\u8c03\u6574\u9971\u548c\u5ea6\u548c\u4eae\u5ea6\u3002\u5f53\u524d\u989c\u8272\u4f1a\u540c\u6b65\u66f4\u65b0 Hex\u3001RGB\u3001HSL\u3001HSV\u3001OKLCH\u3001\u9876\u90e8\u8272\u6761\u3001\u548c\u8c10\u8272\u5757\u548c\u5bfc\u51fa\u9762\u677f\u3002',
    'Primary Colors':'\u539f\u8272',
    'Primary colors are the starting points for many color systems. In traditional art theory they are red, yellow, and blue. On screens, RGB color uses red, green, and blue light to create the colors used in websites, apps, and digital design tools.':'\u539f\u8272\u662f\u8bb8\u591a\u989c\u8272\u7cfb\u7edf\u7684\u8d77\u70b9\u3002\u4f20\u7edf\u827a\u672f\u7406\u8bba\u4e2d\u539f\u8272\u662f\u7ea2\u3001\u9ec4\u3001\u84dd\uff1b\u5728\u5c4f\u5e55\u4e0a\uff0cRGB \u4f7f\u7528\u7ea2\u3001\u7eff\u3001\u84dd\u5149\u6765\u751f\u6210\u7f51\u7ad9\u3001\u5e94\u7528\u548c\u6570\u5b57\u8bbe\u8ba1\u5de5\u5177\u4e2d\u7684\u989c\u8272\u3002',
    'Secondary Colors':'\u4e8c\u6b21\u8272',
    'Secondary colors are created by mixing two primary colors. In a traditional wheel, orange, green, and violet sit between the primary colors and help connect warm, cool, and neutral-feeling palettes.':'\u4e8c\u6b21\u8272\u7531\u4e24\u4e2a\u539f\u8272\u6df7\u5408\u800c\u6210\u3002\u5728\u4f20\u7edf\u8272\u8f6e\u4e2d\uff0c\u6a59\u3001\u7eff\u3001\u7d2b\u4f4d\u4e8e\u539f\u8272\u4e4b\u95f4\uff0c\u5e2e\u52a9\u8fde\u63a5\u6696\u8272\u3001\u51b7\u8272\u548c\u4e2d\u6027\u8272\u8c03\u3002',
    'Tertiary Colors':'\u4e09\u6b21\u8272',
    'Tertiary colors sit between primary and secondary colors. They include combinations such as yellow-orange, red-orange, red-violet, blue-violet, blue-green, and yellow-green, giving a palette more nuance than the basic six-color wheel.':'\u4e09\u6b21\u8272\u4f4d\u4e8e\u539f\u8272\u548c\u4e8c\u6b21\u8272\u4e4b\u95f4\uff0c\u5305\u62ec\u9ec4\u6a59\u3001\u7ea2\u6a59\u3001\u7ea2\u7d2b\u3001\u84dd\u7d2b\u3001\u84dd\u7eff\u3001\u9ec4\u7eff\u7b49\u7ec4\u5408\uff0c\u8ba9\u8c03\u8272\u677f\u6bd4\u57fa\u7840\u516d\u8272\u8272\u8f6e\u66f4\u7ec6\u817b\u3002',
    'Warm and Cool Colors':'\u6696\u8272\u4e0e\u51b7\u8272',
    'Warm colors such as red, orange, and yellow often feel active, bright, and attention-grabbing. Cool colors such as blue, green, and violet can feel calmer and more spacious. A strong palette often uses one temperature as the base and the other as an accent.':'\u7ea2\u3001\u6a59\u3001\u9ec4\u7b49\u6696\u8272\u901a\u5e38\u663e\u5f97\u6d3b\u8dc3\u3001\u660e\u4eae\u4e14\u5438\u5f15\u6ce8\u610f\uff1b\u84dd\u3001\u7eff\u3001\u7d2b\u7b49\u51b7\u8272\u5219\u66f4\u51b7\u9759\u3001\u66f4\u6709\u7a7a\u95f4\u611f\u3002\u5f3a\u914d\u8272\u5e38\u4ee5\u4e00\u79cd\u8272\u6e29\u4e3a\u57fa\u7840\uff0c\u53e6\u4e00\u79cd\u4f5c\u4e3a\u5f3a\u8c03\u3002',
    'Complementary Colors':'\u4e92\u8865\u8272',
    'Complementary colors sit opposite each other on the wheel. They create high contrast and are useful for buttons, highlights, badges, and places where an element needs to stand out from the surrounding interface.':'\u4e92\u8865\u8272\u4f4d\u4e8e\u8272\u8f6e\u76f8\u5bf9\u4f4d\u7f6e\uff0c\u4f1a\u5f62\u6210\u9ad8\u5bf9\u6bd4\uff0c\u9002\u5408\u6309\u94ae\u3001\u9ad8\u4eae\u3001\u5fbd\u7ae0\uff0c\u4ee5\u53ca\u9700\u8981\u4ece\u754c\u9762\u4e2d\u7a81\u51fa\u663e\u793a\u7684\u5143\u7d20\u3002',
    'Analogous Colors':'\u7c7b\u4f3c\u8272',
    'Analogous palettes use neighboring colors on the wheel. Because the hues are close together, the result usually feels smooth, natural, and easier to control across backgrounds, cards, charts, and illustration details.':'\u7c7b\u4f3c\u8272\u8c03\u8272\u677f\u4f7f\u7528\u8272\u8f6e\u4e0a\u7684\u76f8\u90bb\u989c\u8272\u3002\u7531\u4e8e\u8272\u76f8\u63a5\u8fd1\uff0c\u6548\u679c\u901a\u5e38\u66f4\u5e73\u6ed1\u81ea\u7136\uff0c\u4e5f\u66f4\u5bb9\u6613\u63a7\u5236\u80cc\u666f\u3001\u5361\u7247\u3001\u56fe\u8868\u548c\u63d2\u753b\u7ec6\u8282\u3002',
    'Triadic Colors':'\u4e09\u89d2\u8272',
    'Triadic palettes use three hues spaced evenly around the wheel. They can create a vivid but balanced scheme when one color leads and the other two are used more sparingly for accents or supporting elements.':'\u4e09\u89d2\u8272\u8c03\u8272\u677f\u4f7f\u7528\u8272\u8f6e\u4e0a\u7b49\u8ddd\u7684\u4e09\u4e2a\u8272\u76f8\u3002\u5f53\u4e00\u4e2a\u989c\u8272\u4f5c\u4e3a\u4e3b\u8272\uff0c\u53e6\u5916\u4e24\u4e2a\u5c11\u91cf\u7528\u4e8e\u5f3a\u8c03\u6216\u8f85\u52a9\u5143\u7d20\u65f6\uff0c\u53ef\u4ee5\u5f62\u6210\u9c9c\u660e\u800c\u5e73\u8861\u7684\u65b9\u6848\u3002',
    'Split Complementary Colors':'\u5206\u88c2\u4e92\u8865\u8272',
    'A split complementary palette starts with one base color, then uses the two colors next to its direct complement. This gives strong contrast like a complementary scheme, but with a softer and more flexible range.':'\u5206\u88c2\u4e92\u8865\u914d\u8272\u4ece\u4e00\u4e2a\u57fa\u7840\u8272\u5f00\u59cb\uff0c\u518d\u4f7f\u7528\u5176\u76f4\u63a5\u4e92\u8865\u8272\u4e24\u4fa7\u7684\u4e24\u4e2a\u989c\u8272\u3002\u5b83\u50cf\u4e92\u8865\u914d\u8272\u4e00\u6837\u6709\u5f3a\u5bf9\u6bd4\uff0c\u4f46\u8303\u56f4\u66f4\u67d4\u548c\u4e5f\u66f4\u7075\u6d3b\u3002',
    'Tetradic and Square Colors':'\u56db\u8272\u548c\u65b9\u5f62\u914d\u8272',
    'Tetradic and square palettes use four colors around the wheel. They are useful when a design needs several accent colors, but they work best when one color is dominant and the rest are balanced through lighter tints or darker shades.':'\u56db\u8272\u548c\u65b9\u5f62\u914d\u8272\u4f7f\u7528\u8272\u8f6e\u4e0a\u7684\u56db\u4e2a\u989c\u8272\u3002\u5f53\u8bbe\u8ba1\u9700\u8981\u591a\u4e2a\u5f3a\u8c03\u8272\u65f6\u5f88\u6709\u7528\uff0c\u4f46\u6700\u597d\u8ba9\u4e00\u4e2a\u989c\u8272\u5360\u4e3b\u5bfc\uff0c\u5176\u4f59\u901a\u8fc7\u6d45\u8272\u6216\u6df1\u8272\u4fdd\u6301\u5e73\u8861\u3002',
    'Shades, Tints, and Tones':'\u9634\u5f71\u3001\u6d45\u8272\u548c\u8272\u8c03',
    'After choosing a hue relationship, use shades, tints, and tones to make the palette practical. Lighter tints can become backgrounds, darker shades can become text or borders, and muted tones can support secondary UI states.':'\u9009\u62e9\u8272\u76f8\u5173\u7cfb\u540e\uff0c\u53ef\u4ee5\u7528\u9634\u5f71\u3001\u6d45\u8272\u548c\u8272\u8c03\u8ba9\u8c03\u8272\u677f\u66f4\u5b9e\u7528\u3002\u8f83\u6d45\u7684\u989c\u8272\u53ef\u7528\u4e8e\u80cc\u666f\uff0c\u8f83\u6df1\u7684\u989c\u8272\u53ef\u7528\u4e8e\u6587\u5b57\u6216\u8fb9\u6846\uff0c\u67d4\u548c\u8272\u8c03\u53ef\u7528\u4e8e\u6b21\u7ea7\u754c\u9762\u72b6\u6001\u3002',
    'Building a Color Scheme':'\u6784\u5efa\u914d\u8272\u65b9\u6848',
    'Start with the main color, choose a harmony type, then test the result against real interface needs. A complete scheme usually includes a primary color, one or two accents, neutral surfaces, readable text colors, and contrast-safe states.':'\u4ece\u4e3b\u8272\u5f00\u59cb\uff0c\u9009\u62e9\u4e00\u79cd\u548c\u8c10\u7c7b\u578b\uff0c\u518d\u6839\u636e\u771f\u5b9e\u754c\u9762\u9700\u6c42\u6d4b\u8bd5\u7ed3\u679c\u3002\u5b8c\u6574\u65b9\u6848\u901a\u5e38\u5305\u62ec\u4e3b\u8272\u3001\u4e00\u4e24\u4e2a\u5f3a\u8c03\u8272\u3001\u4e2d\u6027\u8868\u9762\u3001\u53ef\u8bfb\u6587\u5b57\u989c\u8272\u548c\u5bf9\u6bd4\u5ea6\u5b89\u5168\u72b6\u6001\u3002',
    'Exporting Wheel Colors':'\u5bfc\u51fa\u8272\u8f6e\u989c\u8272',
    'When the palette feels right, export the colors as CSS variables, Tailwind values, Figma-friendly objects, prefixed color functions, or plain code lists. The same selected color can also be copied directly from any visible swatch.':'\u5f53\u8c03\u8272\u677f\u5408\u9002\u65f6\uff0c\u53ef\u4ee5\u5bfc\u51fa\u4e3a CSS \u53d8\u91cf\u3001Tailwind \u503c\u3001Figma \u53cb\u597d\u5bf9\u8c61\u3001\u5e26\u524d\u7f00\u7684\u989c\u8272\u51fd\u6570\u6216\u7eaf\u4ee3\u7801\u5217\u8868\u3002\u4efb\u4f55\u53ef\u89c1\u8272\u5757\u4e0a\u7684\u5f53\u524d\u989c\u8272\u4e5f\u53ef\u4ee5\u76f4\u63a5\u590d\u5236\u3002',
    'Accessibility and Contrast':'\u65e0\u969c\u788d\u4e0e\u5bf9\u6bd4\u5ea6',
    'Color harmony does not guarantee readability. Check contrast for text and important controls, avoid relying on color alone, and use the simulator to preview how the palette may change for common color vision conditions.':'\u989c\u8272\u548c\u8c10\u4e0d\u4ee3\u8868\u4e00\u5b9a\u53ef\u8bfb\u3002\u8bf7\u68c0\u67e5\u6587\u5b57\u548c\u91cd\u8981\u63a7\u4ef6\u7684\u5bf9\u6bd4\u5ea6\uff0c\u907f\u514d\u53ea\u4f9d\u8d56\u989c\u8272\u4f20\u8fbe\u4fe1\u606f\uff0c\u5e76\u7528\u6a21\u62df\u5668\u9884\u89c8\u5e38\u89c1\u8272\u89c9\u5dee\u5f02\u4e0b\u7684\u8c03\u8272\u677f\u53d8\u5316\u3002'
  };
  function renderLiteTextArticle(sel,items){var mount=document.querySelector(sel);if(!mount)return;clear(mount);items.forEach(function(base,i){var el=document.createElement(i===0?'h2':(i%2?'p':'h3'));el.textContent=routeLang==='zh'?(zhText[base]||base):base;mount.appendChild(el)})}
  function translateLiteStaticZh(){if(routeLang!=='zh')return;var keys=Object.keys(zhText);renderLiteTextArticle('.hcc-info-picker',keys.slice(0,26));renderLiteTextArticle('.hcc-info-wheel',keys.slice(26));Array.prototype.slice.call(document.querySelectorAll('#hccHarmonyMenu button')).forEach(function(btn){btn.textContent=tx(btn.textContent)});Array.prototype.slice.call(document.querySelectorAll('#hccHarmonySelect option')).forEach(function(opt){opt.textContent=tx(opt.textContent)});Array.prototype.slice.call(document.querySelectorAll('.hcc-panel-toggle,#hccStripToggle')).forEach(function(btn){btn.textContent=tx('Toggle')});if(!harmonyChosen&&harmonyButton)harmonyButton.textContent=tx('Choose harmony...')}
  function clamp(v,min,max){return Math.min(max,Math.max(min,v))}
  function clear(el){if(el)while(el.firstChild)el.removeChild(el.firstChild)}
  function block(tag,cls){var el=document.createElement(tag);if(cls)el.className=cls;return el}
  function twoHex(n){n=clamp(Math.round(n),0,255).toString(16);return (n.length<2?'0':'')+n}
  function hsvToRgb(h,s,v){h=(h%360+360)%360;s=s/100;v=v/100;var c=v*s,x=c*(1-Math.abs((h/60)%2-1)),m=v-c,r=0,g=0,b=0;if(h<60){r=c;g=x}else if(h<120){r=x;g=c}else if(h<180){g=c;b=x}else if(h<240){g=x;b=c}else if(h<300){r=x;b=c}else{r=c;b=x}return {r:Math.round((r+m)*255),g:Math.round((g+m)*255),b:Math.round((b+m)*255)}}
  function rgbToHex(r,g,b){return (twoHex(r)+twoHex(g)+twoHex(b)).toUpperCase()}
  function cleanHex(hex){return String(hex||'').replace('#','').trim().toUpperCase()}
  function hexToRgb(hex){hex=cleanHex(hex);if(hex.length===3)hex=hex.replace(/./g,function(c){return c+c});if(!/^[0-9A-F]{6}$/.test(hex))return null;return {r:parseInt(hex.slice(0,2),16),g:parseInt(hex.slice(2,4),16),b:parseInt(hex.slice(4,6),16)}}
  function rgbToHsl(r,g,b){r/=255;g/=255;b/=255;var max=Math.max(r,g,b),min=Math.min(r,g,b),h=0,s=0,l=(max+min)/2,d=max-min;if(d){s=l>.5?d/(2-max-min):d/(max+min);switch(max){case r:h=(g-b)/d+(g<b?6:0);break;case g:h=(b-r)/d+2;break;case b:h=(r-g)/d+4;break}h*=60}return {h:Math.round(h),s:Math.round(s*100),l:Math.round(l*100)}}
