  function rgbToOklch(r,g,b){function lin(v){v/=255;return v<=.04045?v/12.92:Math.pow((v+.055)/1.055,2.4)}var lr=lin(r),lg=lin(g),lb=lin(b),l=Math.cbrt(.4122214708*lr+.5363325363*lg+.0514459929*lb),m=Math.cbrt(.2119034982*lr+.6806995451*lg+.1073969566*lb),s=Math.cbrt(.0883024619*lr+.2817188376*lg+.6299787005*lb),L=.2104542553*l+.793617785*m-.0040720468*s,a=1.9779984951*l-2.428592205*m+.4505937099*s,bb=.0259040371*l+.7827717662*m-.808675766*s,C=Math.sqrt(a*a+bb*bb),H=Math.atan2(bb,a)*180/Math.PI;if(H<0)H+=360;return {l:L.toFixed(2),c:C.toFixed(2),h:Math.round(H)}}
  function lum(rgb){function f(v){v/=255;return v<=.03928?v/12.92:Math.pow((v+.055)/1.055,2.4)}return .2126*f(rgb.r)+.7152*f(rgb.g)+.0722*f(rgb.b)}
  function mix(a,b,t){return {r:Math.round(a.r+(b.r-a.r)*t),g:Math.round(a.g+(b.g-a.g)*t),b:Math.round(a.b+(b.b-a.b)*t)}}
  function current(){var rgb=hsvToRgb(state.h,state.s,state.v),hsl=rgbToHsl(rgb.r,rgb.g,rgb.b),hsv=rgbToHsv(rgb.r,rgb.g,rgb.b),ok=rgbToOklch(rgb.r,rgb.g,rgb.b);return {rgb:rgb,hex:rgbToHex(rgb.r,rgb.g,rgb.b),hsl:hsl,hsv:hsv,ok:ok}}
