  function showToast(text){if(!toast)return;if(toastTimer)clearTimeout(toastTimer);toast.textContent=text||tx('Copied');toast.className='hcc-toast';void toast.offsetWidth;toast.className='hcc-toast show';toastTimer=setTimeout(function(){toast.className='hcc-toast'},1300)}
  function fallbackCopyText(text){var ta=document.createElement('textarea'),ok=false;ta.value=String(text||'');ta.setAttribute('readonly','readonly');ta.style.position='fixed';ta.style.left='-9999px';ta.style.top='0';document.body.appendChild(ta);ta.focus();ta.select();try{ok=document.execCommand('copy')}catch(_){}document.body.removeChild(ta);return ok}
  function copyText(text){var value=String(text||'');fallbackCopyText(value);if(navigator.clipboard&&navigator.clipboard.writeText){navigator.clipboard.writeText(value).catch(function(){fallbackCopyText(value)})}showToast(tx('Copied to clipboard'))}
  function record(hex){hex=cleanHex(hex);if(!hex||hex===history[0])return;history.unshift(hex);history=history.slice(0,18);try{localStorage.setItem('hccLiteHistory',JSON.stringify(history))}catch(_){}}
  function chooseAndCopyHex(hex){var rgb=hexToRgb(hex),h=cleanHex(hex);if(!rgb)return;setFromRgb(rgb);copyText('#'+h)}
  function loadHistory(){try{history=JSON.parse(localStorage.getItem('hccLiteHistory')||'[]').filter(function(v){return /^[0-9A-F]{6}$/.test(cleanHex(v))}).slice(0,18)}catch(_){history=[]}}
  function scaleColors(c){var stops=[.9,.78,.64,.48,.32,.18,0,.18,.34,.5,.64];return stops.map(function(t,i){var target=i<6?{r:255,g:255,b:255}:(i===6?c.rgb:{r:0,g:0,b:0}),rgb=i===6?c.rgb:mix(c.rgb,target,t);return '#'+rgbToHex(rgb.r,rgb.g,rgb.b)})}
  function topStripColors(c){var colors=['#'+c.hex];for(var i=1;i<11;i++){var t=i/10,rgb=mix(c.rgb,{r:128,g:128,b:128},t);colors.push('#'+rgbToHex(rgb.r,rgb.g,rgb.b))}return colors}
  function palette(offsets){return offsets.map(function(o){var rgb=hsvToRgb(state.h+o,state.s,state.v);return '#'+rgbToHex(rgb.r,rgb.g,rgb.b)})}
  function selectedPalette(c){if(!harmonyChosen)return ['#'+c.hex];var v=harmonySelect?harmonySelect.value:'analogous';if(v==='complementary')return palette([0,180]);if(v==='split')return palette([0,150,210]);if(v==='triadic')return palette([0,120,240]);if(v==='tetradic'||v==='square')return palette([0,90,180,270]);return palette([-35,0,35])}
  function fmt(c){var f=formatSelect?formatSelect.value:'Hex';if(f==='RGB')return 'R '+c.rgb.r+'   G '+c.rgb.g+'   B '+c.rgb.b;if(f==='HSL')return 'H '+c.hsl.h+'   S '+c.hsl.s+'   L '+c.hsl.l;if(f==='HSV')return 'H '+Math.round(c.hsv.h)+'   S '+Math.round(c.hsv.s)+'   V '+Math.round(c.hsv.v);if(f==='OKLCH')return 'L '+c.ok.l+'   C '+c.ok.c+'   H '+c.ok.h;return c.hex}
  function renderStrip(c){var strip=document.getElementById('hccTopStrip');clear(strip);topStripColors(c).forEach(function(hex,idx){var rgb=hexToRgb(hex),i=block('i',idx===0?'active':'');var code=cleanHex(hex);i.style.backgroundColor=hex;i.style.setProperty('--strip-text',lum(rgb)>.55?'#000':'#fff');i.style.setProperty('--strip-dot',lum(rgb)>.48?'#000':'#fff');i.setAttribute('data-code',code);i.title='#'+code;i.textContent=code;i.onclick=function(){chooseAndCopyHex(hex)};strip.appendChild(i)})}
  function miniStrip(colors,active,onPick){var wrap=block('span','hcc-mini-strip');wrap.style.gridTemplateColumns='repeat('+colors.length+',1fr)';colors.forEach(function(hex){var i=block('i'),rgb=hexToRgb(hex),code=cleanHex(hex);i.style.backgroundColor=hex;i.style.setProperty('--swatch-text',lum(rgb)>.55?'#000':'#fff');i.setAttribute('data-code',code);i.title='#'+code;i.onclick=function(e){e.preventDefault();e.stopPropagation();if(onPick)onPick(hex)};wrap.appendChild(i)});var dot=block('span','hcc-mini-dot'),rgb=hexToRgb(colors[active||0]);dot.style.setProperty('--dot-left',(((active||0)+.5)/colors.length*100)+'%');dot.style.setProperty('--dot-color',lum(rgb)>.55?'#000':'#fff');wrap.appendChild(dot);return wrap}
